USE ROLE DBA;

USE SCHEMA HAVEN_RAW.COUPA_ETLEAP;

SELECT "pay-invoice_payment-term_content-groups"
FROM INVOICES
where length("pay-invoice_payment-term_content-groups") > 1
limit 100;

desc table invoices;

use schema haven_store.sales_support_restricted;

show tables;

select * from RPT_SALES_SUPPORT_BOOKING_PAYMENT_EXCEPTIONS_DATAMART
limit 10;

